output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?archon ?archonLabel WHERE {
  ?archon rdfs:label ?archonLabel .
  FILTER(langMatches(lang(?archonLabel) , "en"))
  FILTER(CONTAINS(LCASE(?archonLabel) , "archon"))
}

args.sparql:
SELECT ?archon ?archonLabel WHERE {
  ?archon wdt:P31 wd:Q2713331 .
  ?archon rdfs:label ?archonLabel .
  FILTER(langMatches(lang(?archonLabel), "en"))
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en" }
}

SELECT ?item ?itemLabel WHERE {
  ?item rdfs:label "Archon"@en .
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en" }
}
